(function(){var K='mh_cookie_prefs';function h(){var b=document.getElementById('cookie-banner');if(b)b.style.display='none'}function s(a,m){localStorage.setItem(K,JSON.stringify({analytics:a,marketing:m,ts:Date.now()}));h()}if(localStorage.getItem(K))h();document.addEventListener('DOMContentLoaded',function(){if(localStorage.getItem(K))h();var sv=document.getElementById('cookie-save'),ac=document.getElementById('cookie-accept'),rj=document.getElementById('cookie-reject');if(sv)sv.addEventListener('click',function(){s(!!document.getElementById('cookie-analytics')?.checked,!!document.getElementById('cookie-marketing')?.checked)});if(ac)ac.addEventListener('click',function(){s(true,true)});if(rj)rj.addEventListener('click',function(){s(false,false)})})})();
